# Both inputs should produce only `[a-z0-9_]` slugs.
SLUGS=$(jq -r '.[0].features[].feature_slug' shared/cc-adoption-gaps.json | tr '\n' ' ')
if echo "$SLUGS" | grep -qE '^[a-z0-9_ ]+$'; then
  log_pass "Slug sanitization: only [a-z0-9_] chars in output ('$SLUGS')"
else
  log_fail "Slug sanitization" "leaked unsafe chars: '$SLUGS'"
fi

# ============================================================================
# Test 5: parse_failed sentinel preserved — no retry on subsequent runs
# ============================================================================
# Manually set parse_failed and re-run with a valid fixture; entry must remain
