EXIT=0
# silent: known-noise (unset of an unset var is a no-op, not a real failure)
unset CLAUDE_CODE_OAUTH_TOKEN || true
node scripts/cc-triage.mjs > /tmp/cc-triage-out.txt 2>&1 || EXIT=$?

if [ "$EXIT" = "0" ]; then
